static __device__ __forceinline__ uint8_t unpack_3bit(
    const uint8_t * qs, const uint8_t * signs, int j) {
    uint8_t low = (qs[j / 4] >> ((j % 4) * 2)) & 0x3;
    uint8_t hi  = (signs[j / 8] >> (j % 8)) & 0x1;
    return low | (hi << 2);
}
static __device__ __forceinline__ uint8_t unpack_4bit(
    const uint8_t * qs, int j) {
    return (qs[j / 2] >> ((j % 2) * 4)) & 0xF;
}

static __device__ __forceinline__ void dequantize_planar3_0(
    const void * vx, const int64_t ib, const int iqs, float2 & v) {
    const block_planar3_0 * x = (const block_planar3_0 *) vx;
    int p = (int)(iqs >> 1);
    uint8_t idx0 = unpack_3bit(x[ib].qs, x[ib].signs, p*2);
    uint8_t idx1 = unpack_3bit(x[ib].qs, x[ib].signs, p*2+1);
    float norm = __half2float(x[ib].norm);
    v.x = (P3_COS_TABLE[p*8+idx0] + P3_SIN_TABLE[p*8+idx1]) * norm;
    v.y = (P3_COS_TABLE[p*8+idx1] - P3_SIN_TABLE[p*8+idx0]) * norm;
}
static __device__ __forceinline__ void dequantize_planar4_0(
    const void * vx, const int64_t ib, const int iqs, float2 & v) {
    const block_planar4_0 * x = (const block_planar4_0 *) vx;
    int p = (int)(iqs >> 1);
    uint8_t idx0 = unpack_4bit(x[ib].qs, p*2);
    uint8_t idx1 = unpack_4bit(x[ib].qs, p*2+1);
    float norm = __half2float(x[ib].norm);
    v.x = (P4_COS_TABLE[p*16+idx0] + P4_SIN_TABLE[p*16+idx1]) * norm;
    v.y = (P4_COS_TABLE[p*16+idx1] - P4_SIN_TABLE[p*16+idx0]) * norm;
}

// ========================================================================
// ISO dequant __global__ kernels (Phase 1 bulk dequant path)
// ========================================================================

template<typename dst_t>
static __global__ void dequantize_block_iso3_0(
    const void * __restrict__ vx, dst_t * __restrict__ y, const int64_t k) {
    const int64_t qk = 128;
    const int64_t n_groups = 32;
    const int64_t nb = k / qk;
    for (int64_t block = blockIdx.y; block < nb; block += gridDim.y) {
        const block_iso3_0 * xb = &((const block_iso3_0 *) vx)[block];
        float norm = __half2float(xb->norm);
        for (int64_t g = (int64_t)(threadIdx.x + blockIdx.x * blockDim.x);
             g < n_groups;
             g += blockDim.x * gridDim.x) {
            int i0 = (int)(unpack_3bit(xb->qs, xb->signs, (int)(g*4+0)));
            int i1 = (int)(unpack_3bit(xb->qs, xb->signs, (int)(g*4+1)));
            int i2 = (int)(unpack_3bit(xb->qs, xb->signs, (int)(g*4+2)));
            int i3 = (int)(unpack_3bit(xb->qs, xb->signs, (int)(g*4+3)));
            int beg = (int)(g * 8);
            int64_t ibase = block*qk + g*4;
            y[ibase+0] = ggml_cuda_cast<dst_t>(
                (ISO3_QW_TABLE[beg+i0]+ISO3_QX_TABLE[beg+i1]+ISO3_QY_TABLE[beg+i2]+ISO3_QZ_TABLE[beg+i3])*norm);
            y[ibase+1] = ggml_cuda_cast<dst_t>(
                (ISO3_QW_TABLE[beg+i1]-ISO3_QX_TABLE[beg+i0]-ISO3_QY_TABLE[beg+i3]+ISO3_QZ_TABLE[beg+i2])*norm);
            y[ibase+2] = ggml_cuda_cast<dst_t>(
                (ISO3_QW_TABLE[beg+i2]+ISO3_QX_TABLE[beg+i3]-ISO3_QY_TABLE[beg+i0]+ISO3_QZ_TABLE[beg+i1])*norm);
            y[ibase+3] = ggml_cuda_cast<dst_t>(
                (ISO3_QW_TABLE[beg+i3]-ISO3_QX_TABLE[beg+i2]+ISO3_QY_TABLE[beg+i1]-ISO3_QZ_TABLE[beg+i0])*norm);
        }
    }
}

template<typename dst_t>
static __global__ void dequantize_block_iso4_0(
    const void * __restrict__ vx, dst_t * __restrict__ y, const int64_t k) {
    const int64_t qk = 128;
    const int64_t n_groups = 32;
    const int64_t nb = k / qk;
    for (int64_t block = blockIdx.y; block < nb; block += gridDim.y) {
        const block_planar4_0 * xb = &((const block_planar4_0 *) vx)[block];
        float norm = __half2float(xb->norm);
        for (int64_t g = (int64_t)(threadIdx.x + blockIdx.x * blockDim.x);
             g < n_groups;
             g += blockDim.x * gridDim.x) {
            int i0 = (int)(unpack_4bit(xb->qs, (int)(g*4+0)));
            int i1 = (int)(unpack_4bit(xb->qs, (int)(g*4+1)));
            int i2 = (int)(unpack_4bit(xb->qs, (int)(g*4+2)));
            int i3 = (int)(unpack_4bit(xb->qs, (int)(g*4+3)));
            int beg = (int)(g * 16);
            int64_t ibase = block*qk + g*4;
            y[ibase+0] = ggml_cuda_cast<dst_t>(
                (ISO4_QW_TABLE[beg+i0]+ISO4_QX_TABLE[beg+i1]+ISO4_QY_TABLE[beg+i2]+ISO4_QZ_TABLE[beg+i3])*norm);
            y[ibase+1] = ggml_cuda_cast<dst_t>(
                (ISO4_QW_TABLE[beg+i1]-ISO4_QX_TABLE[beg+i0]-ISO4_QY_TABLE[beg+i3]+ISO4_QZ_TABLE[beg+i2])*norm);
            y[ibase+2] = ggml_cuda_cast<dst_t>(
                (ISO4_QW_TABLE[beg+i2]+ISO4_QX_TABLE[beg+i3]-ISO4_QY_TABLE[beg+i0]+ISO4_QZ_TABLE[beg+i1])*norm);
            y[ibase+3] = ggml_cuda_cast<dst_t>(
                (ISO4_QW_TABLE[beg+i3]-ISO4_QX_TABLE[beg+i2]+ISO4_QY_TABLE[beg+i1]-ISO4_QZ_TABLE[beg+i0])*norm);
        }
    }
}

